 if (!_currentRecord.RecordInfo.Contains("（循环完成）"))
 {
 _currentRecord.RecordInfo += "（循环完成）\\n";
 }

 // 将当前记录设为null，下次按键时创建新记录
 _currentRecord = null;

 // 循环完成后重新启用插入新节奏功能
 CanInsertNewBeat = true;
 }
 }
