 return;
 }

 var saveFileDialog = new SaveFileDialog
 {
 Filter = "文本文件 (*.txt)|*.txt|所有文件 (*.*)|*.*",
 Title = "保存节奏配置",
 DefaultExt = ".txt"
 };

 if (saveFileDialog.ShowDialog() == true)
 {
 try
 {
 using (var writer = new System.IO.StreamWriter(saveFileDialog.FileName))
 {
 foreach (var record in BeatRecords)
 {
 writer.WriteLine($"记录信息: {record.RecordInfo}");
 writer.WriteLine($"循环次数: {record.CycleCount}");
 writer.WriteLine("时间点:");
 if (record.Timestamps != null)
 {
 foreach (var timestamp in record.Timestamps)
 {
 writer.WriteLine($" {timestamp:hh\\:mm\\:ss\\.fff}");
 }
 }
 writer.WriteLine(); // 空行分隔
 }
 }

 MessageBox.Show($"节奏配置已保存到：{saveFileDialog.FileName}", "保存成功", MessageBoxButton.OK, MessageBoxImage.Information);
 }
 catch (Exception ex)
 {
 MessageBox.Show($"保存失败：{ex.Message}", "保存错误", MessageBoxButton.OK, MessageBoxImage.Error);
 }
 }
 }

 private bool CanSaveFile()
 {
 return BeatRecords.Count > 0;
