 {
 // 添加安全检查：只有在录制状态、正在播放且有当前记录时才处理
 if (!_isRecording || !IsPlaying || _currentRecord == null)
 {
 return;
 }

 // 确保_startTime已初始化
 if (_startTime == default(DateTime))
 {
 _startTime = DateTime.Now;
 }

 var currentTime = DateTime.Now - _startTime;

 // 确保Timestamps不为null
 if (_currentRecord.Timestamps == null)
 {
 _currentRecord.Timestamps = new ObservableCollection<TimeSpan>();
 }

 _currentRecord.Timestamps.Add(currentTime);

 // 构建当前循环的时间点字符串（用&拼接）
 string currentCycleTimes = string.Join("&", _currentRecord.Timestamps.Select(t => t.ToString("hh:mm:ss.fff")));

 // 如果达到循环次数，完成当前循环
 if (_currentRecord.Timestamps.Count >= _currentRecord.CycleCount)
 {
 // 在当前记录信息中添加当前循环的时间点（用\n分隔）
 if (string.IsNullOrEmpty(_currentRecord.RecordInfo) || _currentRecord.RecordInfo.EndsWith("\n"))
 {
 _currentRecord.RecordInfo += currentCycleTimes + "\n";
 }
 else
 {
 _currentRecord.RecordInfo += "\n" + currentCycleTimes + "\n";
 }

 // 清空时间点列表，准备下一个循环
 _currentRecord.Timestamps.Clear();

 // 重置开始时间以开始新的循环
 _startTime = DateTime.Now;
 }
 else
 {
 // 未完成循环时，更新当前记录信息（用&拼接）
 _currentRecord.RecordInfo = currentCycleTimes;
 }
 }

 // 停止录制
 public void StopBeatRecording()
 {
 _isRecording = false;
 _currentRecord = null;
 CanInsertNewBeat = true; // 停止录制后可以插入新节奏
 StopRecording?.Invoke(this, EventArgs.Empty);
 }

 // 添加停止录制的方法
 public void StopRecordingManually()
 {
 if (_isRecording)
 {
 StopBeatRecording();
 MessageBox.Show("已停止节奏配置", "停止配置", MessageBoxButton.OK, MessageBoxImage.Information);
 }
 }

 private void SaveFile()
 {
 if (BeatRecords.Count == 0)
 {
 MessageBox.Show("没有节奏记录可以保存", "保存失败", MessageBoxButton.OK, MessageBoxImage.Warning);
 return;
 }

 var saveFileDialog = new SaveFileDialog
 {
 Filter = "文本文件 (*.txt)|*.txt|所有文件 (*.*)|*.*",
 Title = "保存节奏配置",
 DefaultExt = ".txt"
 };

 if (saveFileDialog.ShowDialog() == true)
 {
 try
 {
 using (var writer = new System.IO.StreamWriter(saveFileDialog.FileName))
 {
 foreach (var record in BeatRecords)
 {
 writer.WriteLine($"记录信息: {record.RecordInfo}");
 writer.WriteLine($"循环次数: {record.CycleCount}");
 writer.WriteLine("时间点:");
 if (record.Timestamps != null)
 {
 foreach (var timestamp in record.Timestamps)
 {
 writer.WriteLine($" {timestamp:hh\\:mm\\:ss\\.fff}");
 }
 }
 writer.WriteLine(); // 空行分隔
 }
 }

 MessageBox.Show($"节奏配置已保存到：{saveFileDialog.FileName}", "保存成功", MessageBoxButton.OK, MessageBoxImage.Information);
 }
 catch (Exception ex)
 {
 MessageBox.Show($"保存失败：{ex.Message}", "保存错误", MessageBoxButton.OK, MessageBoxImage.Error);
 }
 }
 }

 private bool CanSaveFile()
 {
 return BeatRecords.Count > 0;
 }

 protected virtual void OnPropertyChanged([CallerMemberName] string propertyName = null)
 {
 PropertyChanged?.Invoke(this, new PropertyChangedEventArgs(propertyName));
 }
 }

 // 节奏记录类
 public class BeatRecord
 {
 public int CycleCount { get; set; }
 public string RecordInfo { get; set; }
 public ObservableCollection<TimeSpan> Timestamps { get; set; }
 }
}"}

