 private void SelectFile()
 {
 var openFileDialog = new OpenFileDialog
 {
 Filter = "音频文件 (*.mp3;*.wav;*.flac;*.aac;*.ogg)|*.mp3;*.wav;*.flac;*.aac;*.ogg|所有文件 (*.*)|*.*",
