 SelectedFiles.Add(openFileDialog.FileName);

 // 加载音频文件
 _mediaPlayer.Source = new Uri(openFileDialog.FileName);
 IsPlaying = false;

 MessageBox.Show($"已选择文件：\n{openFileDialog.FileName}", "文件选择成功", MessageBoxButton.OK, MessageBoxImage.Information);
 }
 }

 private void PlayAudio()
 {
 if (_mediaPlayer.Source != null)
 {
 _mediaPlayer.Play();
 IsPlaying = true;
 }
 }

 private bool CanPlayAudio()
 {
 return _mediaPlayer.Source != null && !IsPlaying;
 }

 private void PauseAudio()
 {
 if (_mediaPlayer.Source != null && IsPlaying)
 {
 _mediaPlayer.Pause();
 IsPlaying = false;
 }
 }

 private bool CanPauseAudio()
 {
 return _mediaPlayer.Source != null && IsPlaying;
 }

 protected virtual void OnPropertyChanged([CallerMemberName] string propertyName = null)
 {
 PropertyChanged?.Invoke(this, new PropertyChangedEventArgs(propertyName));
 }
 }
