{"rawEvent":{"message_id":"019bdf6898e078458d1f7ba93c02b4b8","conversation_id":"019bdf6807bb7ad58d597643883850cb","tool_call_id":"call_83edde01-b907-4dcc-b8df-e00c6ef5a356","document":{"file_path":"D:/WindowLearning/BeatCfgMaker/MainWindow.xaml.cs","sub_content":"MainWindow.xaml.cs","sub_content_event":"open_editor","sub_content_event_value":"D:/WindowLearning/BeatCfgMaker/MainWindow.xaml.cs","sub_content_tip":"D:/WindowLearning/BeatCfgMaker/MainWindow.xaml.cs","apply_content":"using System;
using System.Collections.Generic;
using System.Linq;
using System.Text;
using System.Threading.Tasks;
using System.Windows;
using System.Windows.Controls; 
using System.Windows.Data;
using System.Windows.Documents;
using System.Windows.Input;
using System.Windows.Media;
using System.Windows.Media.Imaging;
using System.Windows.Navigation;
using System.Windows.Shapes;

namespace BeatCfgMaker
{
 /// <summary>
 /// MainWindow.xaml 的交互逻辑
 /// </summary>
 public partial class MainWindow : Window
 {
 private MediaElement _mediaPlayer;

 public MainWindow()
 {
 InitializeComponent();

 // 创建MediaElement控件
 _mediaPlayer = new MediaElement
 {
 Volume = 1.0,
 LoadedBehavior = MediaState.Manual,
 UnloadedBehavior = MediaState.Manual
 };

 var viewModel = new MainViewModel();
 DataContext = viewModel;

 // 订阅ViewModel的事件
 viewModel.PlayRequested += OnPlayRequested;
 viewModel.PauseRequested += OnPauseRequested;
 viewModel.PlaybackSpeedChanged += OnPlaybackSpeedChanged;

 _mediaPlayer.MediaEnded += (s, e) => viewModel.IsPlaying = false;
 _mediaPlayer.MediaFailed += (s, e) => 
 {
 viewModel.IsPlaying = false;
 MessageBox.Show($"播放失败：{e.ErrorException?.Message}", "播放错误", MessageBoxButton.OK, MessageBoxImage.Error);
 };
 }

 private void OnPlayRequested(object sender, string audioFile)
 {
 try
 {
 if (_mediaPlayer.Source == null || _mediaPlayer.Source.ToString() != audioFile)
 {
 _mediaPlayer.Source = new Uri(audioFile);
 }

 var viewModel = (MainViewModel)DataContext;
 _mediaPlayer.SpeedRatio = viewModel.PlaybackSpeed;
 _mediaPlayer.Play();
 }
 catch (Exception ex)
 {
 MessageBox.Show($"播放失败：{ex.Message}", "播放错误", MessageBoxButton.OK, MessageBoxImage.Error);
 ((MainViewModel)DataContext).IsPlaying = false;
 }
 }

