using Microsoft.Win32;
using System;
using System.Collections.ObjectModel;
using System.ComponentModel;
using System.Runtime.CompilerServices;
using System.Windows;

namespace BeatCfgMaker
{
    public class MainViewModel : INotifyPropertyChanged
    {
        private ObservableCollection<string> _selectedFiles;

        public event PropertyChangedEventHandler PropertyChanged;

        public RelayCommand SelectFileCommand { get; private set; }
        public RelayCommand SaveFileCommand { get; private set; }
        public ObservableCollection<string> SelectedFiles
        {
            get => _selectedFiles;
            set
            {
                _selectedFiles = value;
                OnPropertyChanged();
            }
        }

        public MainViewModel()
        {
            SelectedFiles = new ObservableCollection<string>();
            SelectFileCommand = new RelayCommand(SelectFile); ;
        }

        private void SelectFile()
        {
            var openFileDialog = new OpenFileDialog
            {
                Filter = "音频文件 (*.mp3;*.wav;*.flac;*.aac;*.ogg)|*.mp3;*.wav;*.flac;*.aac;*.ogg|所有文件 (*.*)|*.*",
                Title = "选择音乐文件",
                Multiselect = true
            };

            if (openFileDialog.ShowDialog() == true)
            {
                SelectedFiles.Clear();
                foreach (var fileName in openFileDialog.FileNames)
                {
                    SelectedFiles.Add(fileName);
                }

                string selectedFiles = string.Join("\n", openFileDialog.FileNames);
                MessageBox.Show($"已选择 {openFileDialog.FileNames.Length} 个文件：\n{selectedFiles}", "文件选择成功", MessageBoxButton.OK, MessageBoxImage.Information);
            }
        }


        protected virtual void OnPropertyChanged([CallerMemberName] string propertyName = null)
        {
            PropertyChanged?.Invoke(this, new PropertyChangedEventArgs(propertyName));
        }
    }
}

using Microsoft.Win32;
using System;
using System.Collections.ObjectModel;
using System.ComponentModel;
using System.Runtime.CompilerServices;
using System.Text.Json;
using System.Windows;

namespace BeatCfgMaker
{
    public class MainViewModel : INotifyPropertyChanged
    {
        private ObservableCollection<string> _selectedFiles;

        public event PropertyChangedEventHandler PropertyChanged;

        public RelayCommand SelectFileCommand { get; private set; }
        public RelayCommand SaveFileCommand { get; private set; }
        public ObservableCollection<string> SelectedFiles
        {
            get => _selectedFiles;
            set
            {
                _selectedFiles = value;
                OnPropertyChanged();
            }
        }

        public MainViewModel()
        {
            SelectedFiles = new ObservableCollection<string>();
            SelectFileCommand = new RelayCommand(SelectFile);
            SaveFileCommand = new RelayCommand(SaveFile, CanSaveFile);
        }

        private void SelectFile()
        {
            var openFileDialog = new OpenFileDialog
            {
                Filter = "音频文件 (*.mp3;*.wav;*.flac;*.aac;*.ogg)|*.mp3;*.wav;*.flac;*.aac;*.ogg|所有文件 (*.*)|*.*",
                Title = "选择音乐文件",
                Multiselect = true
            };

            if (openFileDialog.ShowDialog() == true)
            {
                SelectedFiles.Clear();
                foreach (var fileName in openFileDialog.FileNames)
                {
                    SelectedFiles.Add(fileName);
                }

                string selectedFiles = string.Join("\n", openFileDialog.FileNames);
                MessageBox.Show($"已选择 {openFileDialog.FileNames.Length} 个文件：\n{selectedFiles}", "文件选择成功", MessageBoxButton.OK, MessageBoxImage.Information);
            }
        }

        private void SaveFile()
        {
            if (SelectedFiles.Count == 0)
            {
                MessageBox.Show("请先选择音乐文件", "提示", MessageBoxButton.OK, MessageBoxImage.Warning);
                return;
            }

            var saveFileDialog = new SaveFileDialog
            {
                Filter = "配置文件 (*.json)|*.json|所有文件 (*.*)|*.*",
                Title = "保存配置文件",
                FileName = "music_config.json"
            };

            if (saveFileDialog.ShowDialog() == true)
            {
                try
                {
                    // 这里可以添加实际的配置文件生成逻辑
                    string configContent = GenerateConfigContent();
                    System.IO.File.WriteAllText(saveFileDialog.FileName, configContent);
                    MessageBox.Show($"配置文件已保存到：{saveFileDialog.FileName}", "保存成功", MessageBoxButton.OK, MessageBoxImage.Information);
                }
                catch (Exception ex)
                {
                    MessageBox.Show($"保存文件时出错：{ex.Message}", "错误", MessageBoxButton.OK, MessageBoxImage.Error);
                }
            }
        }

        private bool CanSaveFile()
        {
            return SelectedFiles.Count > 0;
        }

        private string GenerateConfigContent()
        {
            var config = new
            {
                SelectedMusicFiles = SelectedFiles.ToArray(),
                Timestamp = DateTime.Now.ToString("yyyy-MM-dd HH:mm:ss")
            };

            return JsonSerializer.Serialize(config, new JsonSerializerOptions { WriteIndented = true });
        }

        protected virtual void OnPropertyChanged([CallerMemberName] string propertyName = null)
        {
            PropertyChanged?.Invoke(this, new PropertyChangedEventArgs(propertyName));
        }
    }
}

